//! Phase 2 — CERTIFIED COUNTERFACTUAL ROLLOUT: "IF Thoth applies impulse J to A, what is the
//! certified outcome?" derived from what the conservation laws already prove.
//!
//! This is the AGENCY companion to `affordance.rs`: where the affordance gate says WHICH action is
//! admissible, the counterfactual rollout says what the CERTIFIED OUTCOME of an action would be —
//! still with NO force solver and NO ML. Thoth does not simulate dynamics; he forward-images the
//! conserved quantity (momentum) under a HYPOTHETICAL contact impulse and admits the result with the
//! same §7.5 discipline (`accept` / `abstain` / `decline`, each citing a green, Init-only, zero-axiom
//! gnosis-math law). The hypothetical collision (post-impulse A meeting a nearby/absorbing B) is
//! certified by the SAME shared kernel a REAL collision is — `interaction::certify_pair_conservation`.
//!
//! "IF Thoth applies impulse J to A: certified outcome v' = (p + J)/m, would collide with B,
//!  momentum-conserved — UNLESS another force acts." (The conditional honesty of `prediction.rs`.)
//!
//! HONEST BOUNDS (same contract as object_intel / affordance):
//!  * EVERYTHING IS RELATIVE. The impulse J and the resulting v' are in the SAME relative units as the
//!    profile's `momentum` / `speed` — no absolute SI. The certified output is the STRUCTURE (does v'
//!    stay subluminal, does the hypothetical pair conserve momentum), not absolute m/s.
//!  * LIGHTCONE-GATED. A hypothetical impulse that would drive the post-velocity above the scene's
//!    causal-cone ceiling `c_max` is DECLINED under `AckermannLightConeBridge.subluminal_never_reaches_front`
//!    — the same gate the real velocity passes. You cannot counterfactually exceed c.
//!  * REGIME RE-CERT ABSTAINS UNTIL SETTLED. The post-impulse regime cannot be re-certified
//!    instantaneously (a conserved quantity needs frames to establish). Until `hold_min` frames of the
//!    hypothetical free continuation would have accrued, the regime-after ABSTAINS ("too soon to tell")
//!    — honest, never a fabricated post-impulse regime.
//!  * CONDITIONAL. The whole outcome is "unless another force acts" — the forward image of the
//!    conservation, not a claim about the future world.
//!
//! Laws pinned (all green, Init-only, zero-axiom; same provenance as object_intel / interaction):
//!  - momentum after impulse / hypothetical-collision conservation: `ForkRaceFoldVentAreForces.lean:49`
//!    `fork_preserves_charge` — the impulse J adds to the conserved momentum (p' = p + J), and the
//!    hypothetical contact with B conserves the pair's total momentum (Newton's third law for the pair).
//!  - causal post-velocity: `AckermannLightConeBridge.lean:183` `subluminal_never_reaches_front`.

use crate::interaction::certify_pair_conservation;
use crate::object_intel::{Regime, RigidProfile};
use crate::physics::Verdict;

const LAW_CONSERVE: &str = "ForkRaceFoldVentAreForces.fork_preserves_charge";
const LAW_CAUSAL: &str = "AckermannLightConeBridge.subluminal_never_reaches_front";

/// The green gnosis-math law a certified `CertifiedOutcome` predicate is tagged with (re-exported so
/// `SceneModel` can law-tag the emitted predicate). The post-impulse momentum is the conserved
/// quantity (v' = (p+J)/m) and the outcome is admitted only when it is also subluminal.
pub const OUTCOME_LAW: &str = LAW_CONSERVE;

/// The certified outcome of a hypothetical impulse applied to one object.
#[derive(Debug, Clone)]
pub struct CounterfactualOutcome {
    /// The object the impulse would be applied to (the profile's track id).
    pub id: u64,
    /// The hypothetical impulse vector applied (relative units, same as the profile's momentum).
    pub impulse_x: f32,
    pub impulse_y: f32,
    /// Post-impulse velocity v' = (p + J)/m (relative units; component vector + magnitude).
    pub v_after_x: f32,
    pub v_after_y: f32,
    pub speed_after: f32,
    /// The re-certified regime AFTER the impulse, or `Abstain` until `hold_min` frames of the
    /// hypothetical free continuation would accrue ("too soon to tell" — honest).
    pub regime_after: Regime,
    /// §7.5 verdict on the outcome: Accept = a certified causal, momentum-conserving outcome;
    /// Decline = the post-velocity is superluminal (causal gate) OR the hypothetical pair did not
    /// conserve total momentum; Abstain = the regime-after cannot yet be re-certified.
    pub verdict: Verdict,
    /// The green gnosis-math law the outcome is gated under (the binding clause).
    pub law: &'static str,
    /// Human-readable reason (the clause that decided the verdict).
    pub reason: String,
    /// True when the hypothetical collision with the absorber/nearby B conserved total momentum
    /// (certified by the SAME `certify_pair_conservation` kernel a real collision uses).
    pub momentum_conserved: bool,
}

impl CounterfactualOutcome {
    /// True only when the outcome is certified causal AND momentum-conserving (Thoth may rely on it).
    pub fn certified(&self) -> bool {
        self.verdict == Verdict::Accept && self.momentum_conserved
    }

    /// A one-line conditional summary, e.g.
    /// "IF impulse (0.02,0) on #3: v' -> 0.080 u/s, would collide with #7 momentum-conserved (accept) — unless another force acts".
    pub fn summary(&self) -> String {
        format!(
            "IF impulse ({:+.3},{:+.3}) on #{}: v' -> {:.4} u/s [regime-after {}], {} ({}) — unless another force acts  [cites {}]",
            self.impulse_x,
            self.impulse_y,
            self.id,
            self.speed_after,
            self.regime_after.as_str(),
            self.reason,
            self.verdict.as_str(),
            self.law,
        )
    }
}

/// Config for the counterfactual rollout. `momentum_tol` mirrors the interaction detector's tolerance
/// (so the hypothetical pair is certified at the same bar as a real one); `hold_min` mirrors the
/// predictor's regime-hold floor (the post-impulse regime abstains until this many frames would have
/// accrued).
#[derive(Debug, Clone)]
pub struct CounterfactualConfig {
    /// Relative tolerance on the hypothetical pair's total-momentum residual to ACCEPT conservation.
    pub momentum_tol: f32,
    /// Frames of the hypothetical free continuation that must accrue before the post-impulse regime can
    /// be re-certified. Until then the regime-after ABSTAINS ("too soon to tell").
    pub hold_min: u32,
    /// Below this post-impulse speed (relative u/s) the regime-after re-certifies as `AtRest` (the
    /// impulse cancelled the motion); above it, `FreeTranslation` (a free continuation).
    pub rest_speed: f32,
}

impl Default for CounterfactualConfig {
    fn default() -> Self {
        CounterfactualConfig {
            momentum_tol: 0.20,
            hold_min: 4,
            rest_speed: 0.02,
        }
    }
}

/// Certify the outcome of applying a hypothetical impulse `J = (impulse_x, impulse_y)` to object A:
///
///   1. POST-VELOCITY: v' = (p + J)/m where p = m·v is A's certified momentum (fork_preserves_charge:
///      the impulse adds to the conserved momentum). Relative units.
///   2. LIGHTCONE GATE: if |v'| > c_max, DECLINE (subluminal_never_reaches_front) — you cannot
///      counterfactually exceed the causal ceiling.
///   3. HYPOTHETICAL COLLISION: certify the post-impulse A meeting a hypothetical ABSORBER B (a
///      nearby body that takes up the post-impulse momentum, e.g. an inelastic stick to rest) with
///      the SAME `certify_pair_conservation` kernel a real collision uses. Before: A carries p' = p+J,
///      B is at rest (0). After: the inelastic stick gives a common velocity that conserves the pair's
///      total momentum exactly — so the synthetic pair is constructed momentum-consistently and the
///      kernel ACCEPTS (the certification is that the SAME discipline applies to the hypothetical).
///      `absorber_mass` is B's relative mass (default = A's mass: an equal absorber).
///   4. REGIME RE-CERT: ABSTAIN until `hold_min` frames would accrue; once "settled", AtRest if |v'|
///      is below rest_speed (the impulse cancelled the motion) else FreeTranslation.
///
/// `frames_since` is how many frames of the hypothetical free continuation are assumed to have accrued
/// at the moment of assessment — 0 at the instant of the impulse (so the regime-after abstains then),
/// `>= hold_min` once the continuation is established. The honest default for a single-shot rollout is
/// 0 (the regime-after abstains: "too soon to tell"); callers replaying forward pass the accrued count.
pub fn apply_impulse_certified(
    profile: &RigidProfile,
    impulse_x: f32,
    impulse_y: f32,
    absorber_mass: Option<f32>,
    frames_since: u32,
    c_max: f32,
    cfg: &CounterfactualConfig,
) -> CounterfactualOutcome {
    let m = profile.mass.max(1e-9);
    // p' = p + J  (the impulse adds to the conserved momentum; fork_preserves_charge).
    let px = profile.mass * profile.vx;
    let py = profile.mass * profile.vy;
    let p_ax = px + impulse_x;
    let p_ay = py + impulse_y;
    // v' = p'/m.
    let v_after_x = p_ax / m;
    let v_after_y = p_ay / m;
    let speed_after = (v_after_x * v_after_x + v_after_y * v_after_y).sqrt();

    // ── GATE 2: LIGHTCONE (subluminal_never_reaches_front) ──────────────────────────────────────
    if speed_after > c_max {
        return CounterfactualOutcome {
            id: profile.id,
            impulse_x,
            impulse_y,
            v_after_x,
            v_after_y,
            speed_after,
            regime_after: Regime::Abstain,
            verdict: Verdict::Decline,
            law: LAW_CAUSAL,
            reason: format!(
                "post-impulse |v'|={:.4} > c_max={:.4}: a superluminal counterfactual is not admissible — decline",
                speed_after, c_max
            ),
            momentum_conserved: false,
        };
    }

    // ── GATE 3: HYPOTHETICAL COLLISION with an absorber B, certified by the SHARED kernel ────────
    // Construct the synthetic pair momentum-consistently: A carries p' = p+J into a B at rest; the
    // inelastic stick gives the common velocity vf = p'/(m + m_b) that conserves the pair's total
    // momentum. We certify this with `certify_pair_conservation` — the EXACT check a real collision
    // uses — so the hypothetical is admitted the same way a real one is.
    let m_b = absorber_mass.unwrap_or(profile.mass).max(1e-9);
    let total_m = m + m_b;
    let vf_x = p_ax / total_m;
    let vf_y = p_ay / total_m;
    let pa_after = (m * vf_x, m * vf_y);
    let pb_after = (m_b * vf_x, m_b * vf_y);
    let (cons_verdict, residual, cons_reason) = certify_pair_conservation(
        (p_ax, p_ay), // A before the hypothetical contact carries the full post-impulse momentum
        (0.0, 0.0),   // B (absorber) is at rest before
        pa_after,
        pb_after,
        cfg.momentum_tol,
    );
    let momentum_conserved = cons_verdict == Verdict::Accept;
    let _ = residual;
    if !momentum_conserved {
        return CounterfactualOutcome {
            id: profile.id,
            impulse_x,
            impulse_y,
            v_after_x,
            v_after_y,
            speed_after,
            regime_after: Regime::Abstain,
            verdict: Verdict::Decline,
            law: LAW_CONSERVE,
            reason: format!(
                "hypothetical collision with an absorber did NOT conserve total momentum: {} — decline",
                cons_reason
            ),
            momentum_conserved,
        };
    }

    // ── GATE 4: REGIME RE-CERT (abstains until hold_min frames would accrue) ─────────────────────
    let (regime_after, verdict, law, reason) = if frames_since < cfg.hold_min {
        (
            Regime::Abstain,
            Verdict::Abstain,
            LAW_CONSERVE,
            format!(
                "v' = (p+J)/m = {:.4} u/s, hypothetical collision momentum-conserved ({}); regime-after ABSTAINS — only {}/{} frames of the free continuation would have accrued (too soon to re-certify)",
                speed_after, cons_reason, frames_since, cfg.hold_min
            ),
        )
    } else {
        let regime = if speed_after < cfg.rest_speed {
            Regime::AtRest
        } else {
            Regime::FreeTranslation
        };
        (
            regime,
            Verdict::Accept,
            LAW_CONSERVE,
            format!(
                "v' = (p+J)/m = {:.4} u/s (subluminal), hypothetical collision momentum-conserved ({}); regime-after re-certifies {} after {} frames of the free continuation",
                speed_after, cons_reason, regime.as_str(), frames_since
            ),
        )
    };

    CounterfactualOutcome {
        id: profile.id,
        impulse_x,
        impulse_y,
        v_after_x,
        v_after_y,
        speed_after,
        regime_after,
        verdict,
        law,
        reason,
        momentum_conserved,
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::object_intel::{AbstainReason, DENSITY_GUESS, MaterialKind};

    fn mk_profile(vx: f32, vy: f32, mass: f32) -> RigidProfile {
        let speed = (vx * vx + vy * vy).sqrt();
        RigidProfile {
            id: 3,
            genus: 0,
            silhouette_area: 0.05,
            char_size: 0.1,
            depth: 0.5,
            volume: 0.025,
            mass,
            density: DENSITY_GUESS,
            material: MaterialKind::Unknown,
            grounded: false,
            inertia_spin: 0.001,
            vx,
            vy,
            speed,
            momentum: mass * speed,
            ke_lin: 0.5 * mass * speed * speed,
            omega: None,
            ang_momentum: None,
            ke_rot: None,
            regime: Regime::FreeTranslation,
            facts: Vec::new(),
            momentum_spread: 0.0,
            ang_spread: None,
            hold_frames: 6,
            abstain_reason: AbstainReason::None,
        }
    }

    /// COUNTERFACTUAL DECLINES A SUPERLUMINAL IMPULSE: an impulse that would drive v' above c_max is
    /// DECLINED under the lightcone law — you cannot counterfactually exceed the causal ceiling.
    #[test]
    fn counterfactual_declines_superluminal_impulse() {
        let p = mk_profile(0.1, 0.0, 1.0); // p = 0.1
        // c_max = 1.5; an impulse of +2.0 drives v' = (0.1 + 2.0)/1.0 = 2.1 > 1.5.
        let out = apply_impulse_certified(&p, 2.0, 0.0, None, 10, 1.5, &CounterfactualConfig::default());
        assert_eq!(out.verdict, Verdict::Decline, "superluminal v' declines: {}", out.reason);
        assert_eq!(out.law, "AckermannLightConeBridge.subluminal_never_reaches_front");
        assert!(out.speed_after > 1.5, "v' is superluminal: {}", out.speed_after);
    }

    /// MOMENTUM CONSERVED ON THE SYNTHETIC PAIR: a sub-c impulse yields a post-velocity whose
    /// hypothetical inelastic stick with an absorber conserves total momentum (certified by the SAME
    /// kernel a real collision uses). Regime-after accepts once hold_min frames accrue.
    #[test]
    fn counterfactual_momentum_conserved_on_synthetic_pair() {
        let p = mk_profile(0.05, 0.0, 1.0); // p = 0.05
        // Impulse +0.03 => p' = 0.08, v' = 0.08 (sub-c). hold accrued => regime re-certifies.
        let out = apply_impulse_certified(&p, 0.03, 0.0, None, 8, 1.5, &CounterfactualConfig::default());
        assert!(out.momentum_conserved, "synthetic pair conserves momentum: {}", out.reason);
        assert_eq!(out.verdict, Verdict::Accept, "certified outcome: {}", out.reason);
        assert_eq!(out.law, "ForkRaceFoldVentAreForces.fork_preserves_charge");
        assert!((out.speed_after - 0.08).abs() < 1e-4, "v' = (p+J)/m = 0.08: {}", out.speed_after);
        assert_eq!(out.regime_after, Regime::FreeTranslation, "moving free continuation");
        assert!(out.certified());
    }

    /// REGIME-AFTER ABSTAINS TOO SOON: at the instant of the impulse (0 frames of the free continuation
    /// accrued) the regime-after cannot be re-certified — honest "too soon to tell".
    #[test]
    fn counterfactual_regime_after_abstains_too_soon() {
        let p = mk_profile(0.05, 0.0, 1.0);
        let out = apply_impulse_certified(&p, 0.03, 0.0, None, 0, 1.5, &CounterfactualConfig::default());
        assert_eq!(out.regime_after, Regime::Abstain, "0 frames accrued => abstain: {}", out.reason);
        assert_eq!(out.verdict, Verdict::Abstain);
        assert!(out.momentum_conserved, "the conservation still certifies, only the regime abstains");
        assert!(out.reason.contains("too soon"), "{}", out.reason);
    }

    /// A canceling impulse (J = -p) brings the body to rest: v' ~ 0, regime-after re-certifies AtRest.
    #[test]
    fn counterfactual_canceling_impulse_re_certifies_at_rest() {
        let p = mk_profile(0.1, 0.0, 1.0); // p = 0.1
        let out = apply_impulse_certified(&p, -0.1, 0.0, None, 8, 1.5, &CounterfactualConfig::default());
        assert!(out.speed_after < 1e-4, "canceled to rest: {}", out.speed_after);
        assert_eq!(out.regime_after, Regime::AtRest, "v'~0 after hold => at rest: {}", out.reason);
        assert_eq!(out.verdict, Verdict::Accept);
    }
}
